// Generate a random UUID.
// https://stackoverflow.com/questions/105034/create-guid-uuid-in-javascript
function uuidv4() {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
        var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
            return v.toString(16);
    });
}
 
// Check for localStorage support in browser.
function storageAvailable(type) {
   try {
       var x = '__storage_test__';
       window[type].setItem(x, x);
       window[type].removeItem(x);
       return true;
   } catch(e) {
       return false;
   }
}
 
var refreshTokenInProgress = undefined;  // flag to track ongoing refresh token call.
var accessToken = localStorage['accessToken'] ? JSON.parse(localStorage['accessToken']) : null,
    refreshToken = localStorage['refreshToken'] ? JSON.parse(localStorage['refreshToken']) : null;
    
if (accessToken && !refreshToken) {
    refreshTokenInProgress = 1; // set this flag to prevent multiple concurrent refresh calls
    
    var xhr = new XMLHttpRequest(); // create XHR object for access token refresh request.
    xhr.onreadystatechange = function() {
        if(xhr.readyState == XMLHttpRequest.DONE){
            if (xhr.status >= 200 && xhr.status < 400) {
                // If success response received, update localStorage with new access and refresh tokens, clear refreshTokenInProgress flag
                refreshTokenInProgress = undefined;
                accessToken = JSON.parse(xhr.responseText);
                
                localStorage['accessToken'] = JSON.stringify(accessToken);
                localStorage['refreshToken'] = JSON.stringify({
                    'access_token': accessToken['access_token'], 
                    'token_type' : accessToken['token_type'], 
                    'expires_in': accessToken['expires_in'],
                    'refresh_token' : accessToken['refresh_token'] 
                });
            } else {
                refreshTokenInProgress = undefined;
            }
        }
    };
    
    // Request new access token using the existing refresh token.
    xhr.open('POST', '/get-access-token');
    xhr.setRequestHeader("Content-Type", "application/x-www-form-urlencoded");
 
    var body = 'grant_type=refresh_token&' +
        'client_id=' + encodeURIComponent('<KEY>') + '&' +
        'client_secret=' + encodeURIComponent('<KEY>') + '&' + 
        'refresh_token=' + refreshToken.refresh_token;
    xhr.send(body);
}
 
// Helper method to extract access token and token type from HTTP response header.
function extractTokensFromResponseHeader(response) {
    var tokens = {};
    if (!response || !response['getResponseHeaders']) return tokens;
    
    var respHdrs = response.getResponseHeaders(); // Get HTTP response headers object.
    
    for (var i in respHdrs) {
        try {
            var h = respHdrs[i]; // Get response header name, in this case Authorization.
            
            if(h != null && 
                h.length > 0) 
            {
                tokens['access_token'] = h;
                break;
            }
            
        } catch (err){
            console.log('Error: ' + err);
        }
    }
    
    return tokens;
}
 
function refreshOAuth2Tokens() { 
    if (!storageAvailable('localStorage')) 
        return null; // localStorage not supported in browser
 
    var xhr = new XMLHttpRequest(); // create XHR object for access token request.
    xhr.onreadystatechange = function(){
            if(xhr.readyState == XMLHttpRequest.DONE){
                if (xhr.status >= 200 && xhr.status < 400) {
                    // If success response received, extract access and refresh tokens from response header and set to localStorage objects.
                    var tokenJSON = extractTokensFromResponseHeader(xhr);
                    
                    // Update access token in browser storage.
                    if (tokenJSON['access_token'] !== undefined && 
                        tokenJSON['access_token'].length > 0) {
                        accessToken = tokenJSON;
                        
                        localStorage['accessToken'] = JSON.stringify(accessToken); // Access Token
                        refreshTokenInProgress = undefined; // clear refreshTokenInProgress flag
                    } else {
                        alert("Invalid response received in access token request from server.");
                    }
                } else if (xhr.status == 401) {
                    
                    var r = confirm('Access Token expired, click OK to retry the access token call or cancel otherwise.');
                    if (!r) {
                        // Access Token refresh failed prompt user that access token refresh was unsuccessful.
                        return null; 
                    }
                    
                    alert("Access Token Expired, Retrying request....");
                } else  {
                    // If not successful response received in access token request from server.
                    refreshTokenInProgress = undefined; // clear refreshTokenInProgress flag
                    return null;
                }
            }
        };
    
    var body = 'grant_type=refresh_token&' + 
        'client_id=' + encodeURIComponent('<KEY>') + '&' +
        'client_secret=' + encodeURIComponent('<KEY>') + '&' +  
        'refresh_token=' + refreshToken.refresh_token;
    xhr.open('POST', '/get-access-token');
    
    // Set custom request header to set content type for JSON body in POST request. 
    xhr.setRequestHeader("Content-Type", "application/x-www-form-urlencoded");

    // Send access token request.
    xhr.send(body);
}